import { Component, OnDestroy, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { takeUntil } from 'rxjs/operators';
import { Job } from '../models/job.model';
import { DiceApiService } from '../services/dice-api.service';
import { JobService } from '../services/job.service';

type SortColumn = 'role' | 'company' | 'location' | 'score' | 'status' | 'workType' | 'dateUpdated';
type SortDirection = 'asc' | 'desc';

@Component({
  selector: 'app-jobs-grid',
  templateUrl: './jobs-grid.component.html',
  styleUrls: ['./jobs-grid.component.css']
})
export class JobsGridComponent implements OnInit, OnDestroy {
  jobs: Job[] = [];
  filteredJobs: Job[] = [];

  searchText = '';
  selectedStatus = 'All';
  selectedWorkType = 'All';
  minScore: number | null = null;

  sortColumn: SortColumn = 'score';
  sortDirection: SortDirection = 'desc';

  isLoading = false;

  stats = {
    total: 0,
    toApply: 0,
    applied: 0,
    skipped: 0,
    pending: 0
  };

  private destroy$ = new Subject<void>();

  constructor(
    private jobService: JobService,
    private diceApi: DiceApiService,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.jobService.jobs$
      .pipe(takeUntil(this.destroy$))
      .subscribe(jobs => {
        this.jobs = jobs || [];
        this.applyFiltersAndSort();
        this.calculateStats();
      });

    if (!this.jobs.length) {
      this.refreshFromTracker();
    }
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  refreshFromTracker(): void {
    this.isLoading = true;
    this.diceApi.searchEasyApplyJobs()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (jobs) => {
          this.jobService.setJobs(jobs);
          this.isLoading = false;
        },
        error: () => {
          this.isLoading = false;
        }
      });
  }

  onFilterChange(): void {
    this.applyFiltersAndSort();
  }

  onSort(column: SortColumn): void {
    if (this.sortColumn === column) {
      this.sortDirection = this.sortDirection === 'asc' ? 'desc' : 'asc';
    } else {
      this.sortColumn = column;
      this.sortDirection = column === 'score' ? 'desc' : 'asc';
    }
    this.applyFiltersAndSort();
  }

  getSortLabel(column: SortColumn): string {
    if (this.sortColumn !== column) return '';
    return this.sortDirection === 'asc' ? '▲' : '▼';
  }

  private applyFiltersAndSort(): void {
    const search = this.searchText.trim().toLowerCase();

    this.filteredJobs = this.jobs
      .filter(job => {
        if (this.selectedStatus !== 'All' && (job.status || 'To Apply') !== this.selectedStatus) {
          return false;
        }

        if (this.selectedWorkType !== 'All' && (job.workType || 'Unknown') !== this.selectedWorkType) {
          return false;
        }

        if (this.minScore !== null && this.minScore !== undefined && (job.score || 0) < this.minScore) {
          return false;
        }

        if (!search) {
          return true;
        }

        const searchable = [
          job.role,
          job.company,
          job.location,
          job.salary,
          job.summary,
          job.status,
          job.workType,
          job.link
        ]
          .filter(Boolean)
          .join(' ')
          .toLowerCase();

        return searchable.includes(search);
      })
      .sort((a, b) => this.compareJobs(a, b));
  }

  private compareJobs(a: Job, b: Job): number {
    const direction = this.sortDirection === 'asc' ? 1 : -1;

    let left: string | number = '';
    let right: string | number = '';

    switch (this.sortColumn) {
      case 'score':
        left = a.score || 0;
        right = b.score || 0;
        break;
      case 'dateUpdated':
        left = a.dateUpdated || '';
        right = b.dateUpdated || '';
        break;
      case 'role':
        left = a.role || '';
        right = b.role || '';
        break;
      case 'company':
        left = a.company || '';
        right = b.company || '';
        break;
      case 'location':
        left = a.location || '';
        right = b.location || '';
        break;
      case 'status':
        left = a.status || 'To Apply';
        right = b.status || 'To Apply';
        break;
      case 'workType':
        left = a.workType || 'Unknown';
        right = b.workType || 'Unknown';
        break;
      default:
        left = a.score || 0;
        right = b.score || 0;
    }

    if (typeof left === 'number' && typeof right === 'number') {
      return (left - right) * direction;
    }

    return String(left).localeCompare(String(right)) * direction;
  }

  private calculateStats(): void {
    const toApply = this.jobs.filter(j => (j.status || 'To Apply') === 'To Apply').length;
    const applied = this.jobs.filter(j => j.status === 'Applied').length;
    const skipped = this.jobs.filter(j => j.status === 'Skipped').length;
    const pending = this.jobs.filter(j => j.status === 'Pending').length;

    this.stats = {
      total: this.jobs.length,
      toApply,
      applied,
      skipped,
      pending
    };
  }

  trackByLink(index: number, job: Job): string {
    return job.link || String(index);
  }

  loadInWorkflow(job: Job): void {
    this.jobService.setCurrentJob(job);
    this.router.navigate(['/workflow']);
  }

  getStatusClass(status: string | undefined): string {
    switch (status || 'To Apply') {
      case 'Applied':
        return 'status-applied';
      case 'Skipped':
        return 'status-skipped';
      case 'Pending':
        return 'status-pending';
      default:
        return 'status-to-apply';
    }
  }

  clearFilters(): void {
    this.searchText = '';
    this.selectedStatus = 'All';
    this.selectedWorkType = 'All';
    this.minScore = null;
    this.applyFiltersAndSort();
  }
}
<div class="grid-page-container">
  <div class="grid-header">
    <div>
      <h2>Jobs Grid View</h2>
      <p>Complete tracker status table with sorting and filters</p>
    </div>
    <button class="refresh-btn" (click)="refreshFromTracker()" [disabled]="isLoading">
      {{ isLoading ? 'Refreshing...' : 'Refresh from Tracker' }}
    </button>
  </div>

  <div class="stats-row">
    <div class="stat-card total">
      <div class="label">Total</div>
      <div class="value">{{ stats.total }}</div>
    </div>
    <div class="stat-card to-apply">
      <div class="label">To Apply</div>
      <div class="value">{{ stats.toApply }}</div>
    </div>
    <div class="stat-card applied">
      <div class="label">Applied</div>
      <div class="value">{{ stats.applied }}</div>
    </div>
    <div class="stat-card skipped">
      <div class="label">Skipped</div>
      <div class="value">{{ stats.skipped }}</div>
    </div>
    <div class="stat-card pending">
      <div class="label">Pending</div>
      <div class="value">{{ stats.pending }}</div>
    </div>
  </div>

  <div class="filters-panel">
    <div class="filter-group search-group">
      <label for="search">Search</label>
      <input id="search" type="text" [(ngModel)]="searchText" (input)="onFilterChange()" placeholder="Role, company, location, summary, link" />
    </div>

    <div class="filter-group">
      <label for="status">Status</label>
      <select id="status" [(ngModel)]="selectedStatus" (change)="onFilterChange()">
        <option value="All">All</option>
        <option value="To Apply">To Apply</option>
        <option value="Applied">Applied</option>
        <option value="Skipped">Skipped</option>
        <option value="Pending">Pending</option>
      </select>
    </div>

    <div class="filter-group">
      <label for="workType">Work Type</label>
      <select id="workType" [(ngModel)]="selectedWorkType" (change)="onFilterChange()">
        <option value="All">All</option>
        <option value="Remote">Remote</option>
        <option value="Hybrid">Hybrid</option>
        <option value="Onsite">Onsite</option>
        <option value="Unknown">Unknown</option>
      </select>
    </div>

    <div class="filter-group">
      <label for="minScore">Min Score</label>
      <input id="minScore" type="number" [(ngModel)]="minScore" (input)="onFilterChange()" min="0" max="100" />
    </div>

    <div class="filter-group clear-group">
      <button class="clear-btn" (click)="clearFilters()">Clear Filters</button>
    </div>
  </div>

  <div class="table-meta">Showing {{ filteredJobs.length }} of {{ jobs.length }} jobs</div>

  <div class="table-wrapper">
    <table>
      <thead>
        <tr>
          <th (click)="onSort('status')">Status {{ getSortLabel('status') }}</th>
          <th (click)="onSort('role')">Role {{ getSortLabel('role') }}</th>
          <th (click)="onSort('company')">Company {{ getSortLabel('company') }}</th>
          <th (click)="onSort('location')">Location {{ getSortLabel('location') }}</th>
          <th (click)="onSort('workType')">Work Type {{ getSortLabel('workType') }}</th>
          <th (click)="onSort('score')">Score {{ getSortLabel('score') }}</th>
          <th>Salary</th>
          <th>Summary</th>
          <th (click)="onSort('dateUpdated')">Updated {{ getSortLabel('dateUpdated') }}</th>
          <th>Link</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let job of filteredJobs; trackBy: trackByLink" (click)="loadInWorkflow(job)" class="clickable-row">
          <td>
            <span class="status-pill" [ngClass]="getStatusClass(job.status)">{{ job.status || 'To Apply' }}</span>
          </td>
          <td>{{ job.role || 'Role Not Available' }}</td>
          <td>{{ job.company || 'Company Not Available' }}</td>
          <td>{{ job.location || 'Location Not Available' }}</td>
          <td>{{ job.workType || 'Unknown' }}</td>
          <td class="score-cell">{{ job.score || 0 }}</td>
          <td>{{ job.salary || 'N/A' }}</td>
          <td class="summary-cell">{{ job.summary || 'N/A' }}</td>
          <td>{{ job.dateUpdated || job.dateAdded || 'N/A' }}</td>
          <td>
            <a *ngIf="job.link" [href]="job.link" target="_blank" rel="noopener">Open</a>
            <span *ngIf="!job.link">N/A</span>
          </td>
        </tr>
      </tbody>
    </table>
  </div>
</div>
